// Some portions generated by Codex

package org.eclipse.rdf4j.query.algebra.evaluation.sketch;

import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;

class SketchBasedJoinEstimatorSubjectSketchAccuracyTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private final List<SketchBasedJoinEstimator> estimators = new ArrayList<>();

	@AfterEach
	void closeEstimators() {
		for (SketchBasedJoinEstimator estimator : estimators) {
			estimator.close();
		}
		estimators.clear();
	}

	@Test
	void largeFixedSubjectJoinsStayCloseForCommonPredicateAndObjectVariables() {
		StubSketchStatementSource store = new StubSketchStatementSource();
		List<Statement> statements = new ArrayList<>();
		Resource leftSubject = iri("urn:subject-sketch:left");
		Resource rightSubject = iri("urn:subject-sketch:right");

		addPredicateJoinRows(statements, store, leftSubject, rightSubject);
		addObjectJoinRows(statements, store, leftSubject, rightSubject);
		addNoiseRows(statements, store);

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, subjectAccuracyConfig()));
		estimator.rebuild();

		long predicateTruth = truthForFixedSubjects(statements, leftSubject, rightSubject,
				SketchBasedJoinEstimator.Component.P);
		double predicateEstimate = estimator.estimateJoinOn(SketchBasedJoinEstimator.Component.P,
				SketchBasedJoinEstimator.Component.S, leftSubject.stringValue(),
				SketchBasedJoinEstimator.Component.S, rightSubject.stringValue());

		long objectTruth = truthForFixedSubjects(statements, leftSubject, rightSubject,
				SketchBasedJoinEstimator.Component.O);
		double objectEstimate = estimator.estimateJoinOn(SketchBasedJoinEstimator.Component.O,
				SketchBasedJoinEstimator.Component.S, leftSubject.stringValue(),
				SketchBasedJoinEstimator.Component.S, rightSubject.stringValue());

		assertClose("fixed-subject predicate join", predicateTruth, predicateEstimate);
		assertClose("fixed-subject object join", objectTruth, objectEstimate);
	}

	private <T extends SketchBasedJoinEstimator> T track(T estimator) {
		estimators.add(estimator);
		return estimator;
	}

	private static SketchBasedJoinEstimator.Config subjectAccuracyConfig() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withSketchStrategy(SketchBasedJoinEstimator.SketchStrategy.JOIN_SKETCH)
				.withNominalEntries(16_384)
				.withSubjectBucketCount(16_384)
				.withPredicateBucketCount(16_384)
				.withObjectBucketCount(16_384)
				.withContextBucketCount(16_384)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(60_000)
				.withIncrementalQueueEstimatedStatementBytes(1)
				.withMemoryMonitorEstimatedOperationBytes(1);
	}

	private static void addPredicateJoinRows(List<Statement> statements, StubSketchStatementSource store,
			Resource leftSubject, Resource rightSubject) {
		for (int i = 0; i < 420; i++) {
			IRI predicate = iri("urn:subject-sketch:predicate:shared:" + i);
			for (int left = 0; left < 3; left++) {
				add(statements, store, leftSubject, predicate,
						iri("urn:subject-sketch:predicate:left-object:" + i + ":" + left));
			}
			for (int right = 0; right < 5; right++) {
				add(statements, store, rightSubject, predicate,
						iri("urn:subject-sketch:predicate:right-object:" + i + ":" + right));
			}
		}
		for (int i = 0; i < 900; i++) {
			add(statements, store, leftSubject, iri("urn:subject-sketch:predicate:left-only:" + i),
					iri("urn:subject-sketch:predicate:left-only-object:" + i));
			add(statements, store, rightSubject, iri("urn:subject-sketch:predicate:right-only:" + i),
					iri("urn:subject-sketch:predicate:right-only-object:" + i));
		}
	}

	private static void addObjectJoinRows(List<Statement> statements, StubSketchStatementSource store,
			Resource leftSubject, Resource rightSubject) {
		for (int i = 0; i < 360; i++) {
			Resource object = iri("urn:subject-sketch:object:shared:" + i);
			for (int left = 0; left < 4; left++) {
				add(statements, store, leftSubject, iri("urn:subject-sketch:object:left-predicate:" + i + ":" + left),
						object);
			}
			for (int right = 0; right < 2; right++) {
				add(statements, store, rightSubject,
						iri("urn:subject-sketch:object:right-predicate:" + i + ":" + right), object);
			}
		}
		for (int i = 0; i < 900; i++) {
			add(statements, store, leftSubject, iri("urn:subject-sketch:object:left-only-predicate:" + i),
					iri("urn:subject-sketch:object:left-only:" + i));
			add(statements, store, rightSubject, iri("urn:subject-sketch:object:right-only-predicate:" + i),
					iri("urn:subject-sketch:object:right-only:" + i));
		}
	}

	private static void addNoiseRows(List<Statement> statements, StubSketchStatementSource store) {
		for (int i = 0; i < 18_000; i++) {
			add(statements, store, iri("urn:subject-sketch:noise:s:" + i),
					iri("urn:subject-sketch:noise:p:" + (i % 2_000)),
					iri("urn:subject-sketch:noise:o:" + (i % 3_000)));
		}
	}

	private static void add(List<Statement> statements, StubSketchStatementSource store, Resource subject,
			IRI predicate, Value object) {
		Statement statement = VF.createStatement(subject, predicate, object);
		statements.add(statement);
		store.add(statement);
	}

	private static long truthForFixedSubjects(List<Statement> statements, Resource leftSubject, Resource rightSubject,
			SketchBasedJoinEstimator.Component joinComponent) {
		Map<Value, Integer> leftCounts = new HashMap<>();
		Map<Value, Integer> rightCounts = new HashMap<>();
		for (Statement statement : statements) {
			Map<Value, Integer> counts;
			if (leftSubject.equals(statement.getSubject())) {
				counts = leftCounts;
			} else if (rightSubject.equals(statement.getSubject())) {
				counts = rightCounts;
			} else {
				continue;
			}
			Value key = switch (joinComponent) {
			case P -> statement.getPredicate();
			case O -> statement.getObject();
			case S, C -> throw new IllegalArgumentException("Unsupported fixed-subject join component: "
					+ joinComponent);
			};
			counts.merge(key, 1, Integer::sum);
		}
		long rows = 0L;
		for (Map.Entry<Value, Integer> left : leftCounts.entrySet()) {
			rows += (long) left.getValue() * rightCounts.getOrDefault(left.getKey(), 0);
		}
		return rows;
	}

	private static void assertClose(String label, long truth, double estimate) {
		double relativeError = Math.abs(estimate - truth) / Math.max(1.0d, truth);
		System.out.println(label + ": truth=" + truth + ", estimate=" + estimate + ", relativeError="
				+ relativeError);
		assertTrue(truth > 0L, label + " truth should be positive");
		assertTrue(relativeError <= 0.05d,
				() -> label + " relative error too high: truth=" + truth + ", estimate=" + estimate
						+ ", relativeError=" + relativeError);
	}

	private static IRI iri(String value) {
		return VF.createIRI(value);
	}
}
